function validateRouteParameter(req, res, next) {
  const routeParameter = req.params.id;
  const regex = /^[0-9]+$/;
  if (regex.test(routeParameter)) {
    req.routeParameter = parseInt(routeParameter);
    if (req.routeParameter > 0) {
      next();
    } else {
      next(new Error('Invalid route parameter'));
    }
  } else {
    const regexStr = /^[a-zA-Z]+$/;
    if (regexStr.test(routeParameter)) {
      req.routeParameter = routeParameter;
      next();
    } else {
      next(new Error('Invalid route parameter'));
    }
  }
}

