class Solution:
  def validateRouteParameter(self, req, res, next):
    routeParameter = req.params['id']
    regex = re.compile(r'^[0-9]+$')
    if regex.match(routeParameter):
      req.routeParameter = int(routeParameter)
      if req.routeParameter > 0:
        next()
      else:
        next(ValueError('Invalid route parameter'))
    else:
      regexStr = re.compile(r'^[a-zA-Z]+$')
      if regexStr.match(routeParameter):
        req.routeParameter = routeParameter
        next()
      else:
